INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('land-agent-moex-00146', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「背後是山，前面是海，這是一個沒有耕地的地方。人是靠糧食而活的，然而，並不是 說沒有耕地就無法活下去。這裡的人們，便把大海當成他們的田畝，克勤克儉的經營著。 當蘭陽的原野上忙著豐收的時候，他們也同樣的在浩浩的海洋田畝裡忙著收穫，忙著裝 載，忙著運送。港灣裡，有千桅高挺著，也有千百個硬朗的漢子站立著。在這裡，每一 根船桅都是一枝生命的標竿，每一條漢子都是一座力的源泉。因此，不管海有多寬、洋 有多遠，他們都能夠在上面踩出縱縱橫橫的道路來；只要鼓帆，只要發動馬達，便可以 去千百里。……這裡的人們，也許不一定都會讀懂那些厚部頭書，可是，他們卻能夠讀 得懂海洋。比起那些書來，海洋是難懂得多了，而這裡的人們卻有能力消化它。甚至， 連那些耄耋老者或是年幼的童子，以及那些漁婦漁姑都不例外。」 依據上文，下列敘述錯誤的是：', '["敘述漁民具有代代相傳的堅毅性格", "刻畫漁民生活樣貌，而他們都是勞動者典範", "描述一面討海與一面耕地是當地漁民的生活方式", "描寫漁民克勤克儉地營生，表現出堅毅與勤勉的精神"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00147', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「歸有光的〈項脊軒志〉最後三句是︰『庭有枇杷樹，吾妻死之年所手植也，今已亭亭 如蓋矣！』要寫景，實在有很多處可入手，何必只寫這一棵枇杷樹？要記事，也不少， 又何必要寫這棵樹的小事。其實最重要的，就是『吾妻死之年』五個字，為這五字而記， 否則不能記。有什麼情感呢？就是在一個『已』字下看出來。回想前情，宛然在目；樹 已亭亭如蓋，人面不知何處？」 下列選項，何者最符合本段主旨？', '["樹大招風風撼樹", "十年樹木，百年樹人", "樹猶如此，人何以堪", "渭北春天樹，江東日暮雲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00148', 'land-agent', 'land-agent-moex-107-9a386a01', 'sub-land-agent-05', NULL, 'single_choice', '「謹慎自愛本是美德，但是倘若過分，就變成畏縮無能。在戰壕裡，戰士倘若開槍射擊， 就容易使敵人瞄準他的位置，但是一槍不放的戰士又如何立功？多做多錯，少做少錯， 不做不錯，這話的確是經驗之談，但是發明這句話的人可曾想過：不做不錯的『不錯』， 到底有什麼價值？」 本文旨在說明：', '["凡人欲建功立業，則須謹慎，如履薄冰、兢兢業業", "凡事須力求完美，事先精心規劃，盡可能避免錯誤", "處事須行中庸之道才能明哲保身，過與不及都不好", "做事勇於挑戰、勇於負責，不怕犯錯才能有所成就"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "b69e8e076c7c", "answer_pdf_sha1": "15960b581ada", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00149', 'land-agent', 'land-agent-moex-107-8c177526', 'sub-land-agent-01', NULL, 'essay', '我國土地法地籍編及民法物權編相關規定，不動產物權登記係採登記生效主義，非
經依法登記不生效力。試問某甲擅將某乙所有土地移轉登記於甲自己名下所有，並
設定抵押權登記給善意之某丙，則某乙能否訴請塗銷某甲之所有權移轉登記及某丙
之抵押權登記？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:15+00:00", "source_pdf_sha1": "57a86962faaa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "201", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "land", "db_exam_id": "land-agent"}'::jsonb, NULL),
  ('land-agent-moex-00150', 'land-agent', 'land-agent-moex-107-8c177526', 'sub-land-agent-01', NULL, 'essay', '依法照價收買之土地，地上如有農作改良物，主管機關應如何估定補償？試依平均
